const html = $json.data;
const urlOrigem = $node["Ler_Fontes_de_Busca"].json.url;
const nomeFonte = $node["Ler_Fontes_de_Busca"].json.nome_fonte;

if (!html) return [];

const match = html.match(/<script id="__NEXT_DATA__" type="application\/json">([\s\S]*?)<\/script>/);
if (!match) return [];

try {
  const data = JSON.parse(match[1]);
  const jobs = data.props.pageProps.jobs || [];
  const pattern = /aprendiz/i;
  const filteredJobs = jobs.filter(j => pattern.test(j.title));

  return filteredJobs.map(v => {
    const jobUrl = `${urlOrigem.replace(/\/$/, '')}/jobs/${v.id}`;
    const seed = jobUrl;
    let hash = 0;
    for (let i = 0; i < seed.length; i++) {
      const char = seed.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    const id = 'vaga_scr_' + Math.abs(hash).toString(36) + '_' + seed.length.toString(36);

    let localidade = 'Remoto';
    if (v.workplace && v.workplace.address) {
      const addr = v.workplace.address;
      localidade = `${addr.city || ''} - ${addr.stateShortName || ''}`.replace(/^ - | - $/g, '');
    }

    return {
      id,
      titulo: v.title,
      empresa: nomeFonte,
      localidade: localidade || 'Não especificado',
      descricao: `Vaga de Jovem Aprendiz no departamento ${v.department || 'Geral'}. Tipo: ${v.type || 'Aprendizado'}. Candidate-se no link original.`,
      url: jobUrl,
      origem: nomeFonte,
      data_publicacao: new Date().toISOString().split('T')[0],
      status: "PENDENTE",
      data_descoberta: new Date().toISOString()
    };
  });
} catch (e) {
  return [];
}

const items = $input.all();
const parserItems = $items('Parser_de_Vagas');
const result = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (item.json.vaga_existe === false || item.json.vaga_existe === 'false') {
    const parserData = parserItems[i] ? parserItems[i].json : item.json;
    result.push({ json: { ...parserData, vaga_nova: true } });
  }
}
return result;

const html = $input.first().json.data;
const orig = $node['Loop_Vagas'].json;

let cleanDesc = orig.descricao || '';

if (html) {
  const match = html.match(/<script id="__NEXT_DATA__" type="application\/json">([\s\S]*?)<\/script>/);
  if (match) {
    try {
      const parsed = JSON.parse(match[1]);
      const job = parsed.props.pageProps.job;
      if (job) {
        let descParts = [];
        if (job.description && job.description.trim() !== '<p><br></p>') {
          descParts.push(`<h3>Sobre a vaga / Empresa:</h3>${job.description}`);
        }
        if (job.responsibilities && job.responsibilities.trim() !== '<p><br></p>') {
          descParts.push(`<h3>Responsabilidades e atribuições:</h3>${job.responsibilities}`);
        }
        if (job.prerequisites && job.prerequisites.trim() !== '<p><br></p>') {
          descParts.push(`<h3>Requisitos e qualificações:</h3>${job.prerequisites}`);
        }
        if (job.relevantExperiences && job.relevantExperiences.trim() !== '<p><br></p>') {
          descParts.push(`<h3>Informações adicionais / Benefícios:</h3>${job.relevantExperiences}`);
        }

        if (descParts.length > 0) {
          cleanDesc = descParts.join('\n');
        }
      }
    } catch (e) {
      // Fallback
    }
  }
}

return {
  json: {
    ...orig,
    descricao: cleanDesc
  }
};
